import { useState } from 'react';

interface Todo {
  id: number;
  text: string;
  completed: boolean;
}

const INITIAL_TODOS: Todo[] = [
  { id: 1, text: 'Review pull request', completed: false },
  { id: 2, text: 'Write unit tests', completed: true },
  { id: 3, text: 'Update documentation', completed: false },
  { id: 4, text: 'Deploy to staging', completed: false },
];

function simulateSave(id: number): Promise<void> {
  return new Promise((resolve, reject) =>
    setTimeout(() => (Math.random() < 0.4 ? reject(new Error('Save failed')) : resolve()), 800)
  );
}

export default function App() {
  const [todos, setTodos] = useState<Todo[]>(INITIAL_TODOS);
  const [pendingIds, setPendingIds] = useState<Set<number>>(new Set());
  const [errors, setErrors] = useState<Record<number, string>>({});

  async function handleToggle(id: number) {
    // Capture snapshot before mutation for potential rollback
    const previous = todos;

    // Mark in-flight
    setPendingIds(prev => new Set(prev).add(id));
    // Clear any previous error on this item
    setErrors(prev => { const next = { ...prev }; delete next[id]; return next; });

    // Optimistic update
    setTodos(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t));

    try {
      await simulateSave(id);
    } catch {
      // Rollback
      setTodos(previous);
      setErrors(prev => ({ ...prev, [id]: 'Failed — rolled back' }));
      // Auto-clear error after 3s
      setTimeout(() => setErrors(prev => { const next = { ...prev }; delete next[id]; return next; }), 3000);
    } finally {
      setPendingIds(prev => { const next = new Set(prev); next.delete(id); return next; });
    }
  }

  return (
    <div style={{ padding: '2rem', maxWidth: '28rem' }}>
      <h2 style={{ fontWeight: 700, marginBottom: '1rem' }}>Todos</h2>
      <ul style={{ listStyle: 'none', padding: 0, display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
        {todos.map(todo => (
          <li key={todo.id} style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', padding: '0.5rem', border: '1px solid #e5e7eb', borderRadius: '0.375rem' }}>
            <input
              type="checkbox"
              checked={todo.completed}
              disabled={pendingIds.has(todo.id)}
              onChange={() => handleToggle(todo.id)}
              style={{ cursor: pendingIds.has(todo.id) ? 'wait' : 'pointer' }}
            />
            <span style={{ flex: 1, textDecoration: todo.completed ? 'line-through' : 'none', color: todo.completed ? '#9ca3af' : 'inherit' }}>{todo.text}</span>
            {pendingIds.has(todo.id) && <span style={{ fontSize: '0.75rem', color: '#f59e0b' }}>saving…</span>}
            {errors[todo.id] && <span style={{ fontSize: '0.75rem', color: '#ef4444' }}>{errors[todo.id]}</span>}
          </li>
        ))}
      </ul>
    </div>
  );
}
